section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/microservices-observability.json",
  "type": "object",
  "required": [
    "service_name",
    "logs_structured",
    "metrics_red",
    "tracing_otel",
    "propagator",
    "log_trace_id_present"
  ],
  "properties": {
    "service_name": {
      "type": "string",
      "pattern": "^[a-z][a-z0-9-]+$"
    },
    "logs_structured": {
      "type": "boolean",
      "const": true
    },
    "metrics_red": {
      "type": "boolean",
      "const": true
    },
    "tracing_otel": {
      "type": "boolean",
      "const": true
    },
    "propagator": {
      "enum": [
        "w3c",
        "b3-fallback"
      ]
    },
    "log_trace_id_present": {
      "type": "boolean",
      "const": true
    },
    "otlp_endpoint": {
      "type": "string",
      "format": "uri"
    },
    "slo_targets": {
      "type": "object",
      "properties": {
        "availability": {
          "type": "number"
        },
        "p99_latency_ms": {
          "type": "integer"
        }
      }
    },
    "pii_in_spans": {
      "type": "boolean",
      "const": false
    }
  },
  "additionalProperties": false
}
